sys_ui_action.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
// KT - REQUEST TYPE

var errorMessage = 'Request ' + current.number + ' did not meet the conditions to submit a Reject Extension';

if(current.u_request_type == "Extension" &&
	current.parent != "" &&
	current.parent.state == 13 &&
	current.parent.extension_requested == true &&
	new UserInfoScripts().IsUserTaskingAuthority(current.parent.primary_assignee, gs.getUserID())) {

	var taskWorkNotes = 'Extension Request has been rejected by ' + gs.getUserDisplayName() + 
		' with the following comments: ' + current.u_response_comments + '. Note: The suspense date has not been updated.';

	//KT: Update Task table
	var parentId = current.parent.toString();
	var grTask = new GlideRecord("x_153465_discovert_route_task_instance");
	if (grTask.get(parentId)){

		var allow = new uiConditionCheck().RespondExtension(grTask);

		if (allow) {
			// STRY0077968, STRY0084290
			grTask.latest_extension_request_date = current.u_requested_suspense_date;
			grTask.extended_suspense_date = '';

			grTask.extension_approval = 'Rejected';
			grTask.extension_requested = false;
			grTask.work_notes = taskWorkNotes;
			grTask.update();

			//KT: Update Request table
			var todaysDate = new GlideDateTime();
			current.u_status = 'Completed'; //'Approved';
			current.u_response = 'Rejected';
			current.u_responded_by = gs.getUserID();
			current.u_responded = todaysDate;
			current.update();

			//KT: Show Confirmation Message
			gs.addInfoMessage(taskWorkNotes);

		} else gs.addErrorMessage(errorMessage);
	}

} else gs.addErrorMessage(errorMessage);
